from flask import Flask, request
import werkzeug

app = Flask(__name__)

@app.route('/upload', methods=['POST'])
def upload_file():
    file = request.files['image']
    filename = werkzeug.utils.secure_filename(file.filename)
    file.save(filename)
    return 'File uploaded successfully'
    
if __name__ == '__main__':
    app.run(debug = True)